import requests

def create_vhost(rabbitmq_host, rabbitmq_port, vhost):
    url = f'http://{rabbitmq_host}:{rabbitmq_port}/api/vhosts/{vhost}'
    response = requests.put(url)
    if response.status_code == 201:
        print(f'Vertical host {vhost} created successfully')
    else:
        print(f'Error creating vertical host {vhost}: {response.text}')

def create_user(rabbitmq_host, rabbitmq_port, vhost, username):
    url = f'http://{rabbitmq_host}:{rabbitmq_port}/api/users'
    data = {'name': username, 'password': 'your_password', 'vhosts': [vhost]}
    response = requests.put(url, json=data)
    if response.status_code == 201:
        print(f'User {username} created successfully')
    else:
        print(f'Error creating user {username}: {response.text}')

def grant_permission(rabbitmq_host, rabbitmq_port, vhost, username):
    url = f'http://{rabbitmq_host}:{rabbitmq_port}/api/permissions/{vhost}'
    data = {'user': username, 'configure': '.*', 'write': '^amq\.gen.*$', 'read': '.*'}
    response = requests.put(url, json=data)
    if response.status_code == 201:
        print(f'Permission granted for user {username} in vhost {vhost} successfully')
    else:
        print(f'Error granting permission for user {username} in vhost {vhost}: {response.text}')

# RabbitMQ credentials
rabbitmq_host = 'your_rabbitmq_host'
rabbitmq_port = 15672

# Create vertical hosts
vhosts = ['app1', 'app2', 'app3']
for vhost in vhosts:
    create_vhost(rabbitmq_host, rabbitmq_port, vhost)

# Create users and grant permissions
users = {
    'app1': 'user_app1',
    'app2': 'user_app2',
    'app3': 'user_app3'
}
for app, username in users.items():
    create_user(rabbitmq_host, rabbitmq_port, app, username)
    grant_permission(rabbitmq_host, rabbitmq_port, app, username)